// Categorize changes by severity
const changes = $input.all().map(item => item.json);

const categorized = {
  critical: [],
  warning: [],
  info: []
};

changes.forEach(change => {
  let severity;

  switch(change.change_type) {
    case 'lost_ranking':
    case 'major_drop':
      severity = 'critical';
      break;
    case 'drop':
      severity = 'warning';
      break;
    case 'new_ranking':
    case 'major_gain':
    case 'gain':
      severity = 'info';
      break;
    default:
      return;
  }

  categorized[severity].push({
    keyword: change.keyword,
    change_type: change.change_type,
    yesterday_position: change.yesterday_position,
    today_position: change.today_position,
    position_change: change.position_change,
    priority: change.priority,
    target_url: change.target_url,
    today_url: change.today_url
  });
});

const hasAlerts = categorized.critical.length > 0 || categorized.warning.length > 0;

return [{
  json: {
    has_alerts: hasAlerts,
    categorized,
    counts: {
      critical: categorized.critical.length,
      warning: categorized.warning.length,
      info: categorized.info.length,
      total: changes.length
    }
  }
}];

// Create alert records for significant changes
const data = $input.first().json;
const alerts = [];
const today = new Date().toISOString().split('T')[0];

// Critical alerts
data.categorized.critical.forEach(change => {
  alerts.push({
    alert_type: change.change_type === 'lost_ranking' ? 'ranking_lost' : 'ranking_drop',
    severity: 'critical',
    title: change.change_type === 'lost_ranking' 
      ? `Lost Ranking: "${change.keyword}"`
      : `Major Drop: "${change.keyword}" (#${change.yesterday_position} → #${change.today_position})`,
    message: `Keyword "${change.keyword}" ${change.change_type === 'lost_ranking' ? 'is no longer ranking' : `dropped ${Math.abs(change.position_change)} positions`}`,
    metadata: JSON.stringify(change)
  });
});

// Warning alerts
data.categorized.warning.forEach(change => {
  alerts.push({
    alert_type: 'ranking_drop',
    severity: 'warning',
    title: `Ranking Drop: "${change.keyword}" (#${change.yesterday_position} → #${change.today_position})`,
    message: `Keyword "${change.keyword}" dropped ${Math.abs(change.position_change)} positions`,
    metadata: JSON.stringify(change)
  });
});

return alerts.map(a => ({ json: a }));
